function FloatField({ id, label }) {
  const [active, setActive] = React.useState(false);
  return (
    <div style={{ position: 'relative' }}>
      <input id={id} placeholder=" "
        onFocus={() => setActive(true)}
        onBlur={(e) => setActive(!!e.target.value)}
        style={{ padding: '16px 12px 8px', border: '1px solid #D1D5DB', borderRadius: 8 }}
      />
      <motion.label htmlFor={id}
        animate={active ? { y: -22, fontSize: 11, color: '#6366F1' } : { y: 0, fontSize: 14, color: '#94A3B8' }}
        transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
        style={{ position: 'absolute', left: 12, top: 14, background: '#fff', padding: '0 4px' }}
      >{label}</motion.label>
    </div>
  );
}

