function ShopTilt({ children }) {
  const x = useMotionValue(0); const y = useMotionValue(0);
  const rotateX = useTransform(y, [-50, 50], [1.5, -1.5]);
  const rotateY = useTransform(x, [-50, 50], [-2, 2]);
  return (
    <motion.div
      onMouseMove={(e) => { const r = e.currentTarget.getBoundingClientRect(); x.set(e.clientX - r.left - r.width / 2); y.set(e.clientY - r.top - r.height / 2); }}
      onMouseLeave={() => { x.set(0); y.set(0); }}
      style={{ rotateX, rotateY, transformStyle: 'preserve-3d', perspective: 1000 }}
    >
      {children}
    </motion.div>
  );
}

